// --- Sync Manager (higher-level sync orchestration) ---

class SyncManager {
  final ApiClient _apiClient;
  DateTime? _lastSyncedAt;
  bool _isSyncing = false;
  Timer? _periodicSyncTimer;

  // Callbacks
  final Future<List<SyncData>> Function() getLocalChanges;
  final Future<void> Function(List<SyncData> remoteChanges) applyRemoteChanges;
  final Future<void> Function(DateTime syncedAt) onSyncComplete;

  SyncManager({
    required ApiClient apiClient,
    required this.getLocalChanges,
    required this.applyRemoteChanges,
    required this.onSyncComplete,
    DateTime? lastSyncedAt,
  })  : _apiClient = apiClient,
        _lastSyncedAt = lastSyncedAt;

  bool get isSyncing => _isSyncing;

  Future<SyncResult?> syncNow() async {
    if (_isSyncing) return null;
    if (!_apiClient.isAuthenticated) return null;

    _isSyncing = true;

    try {
      final localChanges = await getLocalChanges();

      final result = await _apiClient.syncData(
        localChanges: localChanges,
        lastSyncedAt: _lastSyncedAt,
      );

      if (result.pulled.isNotEmpty) {
        await applyRemoteChanges(result.pulled);
      }

      _lastSyncedAt = result.syncedAt;
      await onSyncComplete(result.syncedAt);

      return result;
    } on UnauthorizedException {
      rethrow;
    } on NetworkException {
      // Silently fail on network issues; will retry later
      return null;
    } catch (e) {
      rethrow;
    } finally {
      _isSyncing = false;
    }
  }

  void startPeriodicSync({Duration interval = const Duration(minutes: 5)}) {
    stopPeriodicSync();
    _periodicSyncTimer = Timer.periodic(interval, (_) => syncNow());
  }

  void stopPeriodicSync() {
    _periodicSyncTimer?.cancel();
    _periodicSyncTimer = null;
  }

  void dispose() {
    stopPeriodicSync();
  }
}

